      teleportMap[i] = [];

      for (let j = 0; j < n; j++) {

         teleportMap[i][j] = [];

         for (let x = 0; x < m; x++) {

            for (let y = 0; y < n; y++) {

               if (grid[x][y] <= grid[i][j]) {

                  teleportMap[i][j].push([x, y]);

               }

            }

         }

      }

   }

   // Now, Dijkstra's algorithm.

   // Initialize distance array.

   const INF = Infinity;

   const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k+1).fill(INF)));

   dist[0][0][0] = 0;

   // Priority queue: [cost, i, j, t]

   const heap: [number, number, number, number][] = [];

   heap.push([0, 0, 0, 0]);

   // Directions for regular moves: right and down.

   const directions = [[0, 1], [1, 0]];

   while (heap.length > 0) {

      // Get the state with minimal cost.

      const [cost, i, j, t] = heap.shift()!;

      // If we have already found a better path to (i,j,t), skip.

      if (cost > dist[i][j][t]) {

