      // If we have reached the destination.

      if (i === m-1 && j === n-1) {

         return cost;

      }

      // Process regular moves.

      for (const [dx, dy] of directions) {

         const ni = i + dx;

         const nj = j + dy;

         if (ni >= 0 && ni < m && nj >= 0 && nj < n) {

            const new_cost = cost + grid[ni][nj];

            if (new_cost < dist[ni][nj][t]) {

               dist[ni][nj][t] = new_cost;

               heap.push([new_cost, ni, nj, t]);

            }

         }

      }

      // Process teleport moves.

      if (t < k) {

         for (const [x, y] of teleportMap[i][j]) {

            const new_t = t + 1;

            if (cost < dist[x][y][new_t]) {

               dist[x][y][new_t] = cost;

               heap.push([cost, x, y, new_t]);

            }

         }

      }

   }

   // If not found, return something? But the problem says it's always possible.

