use std::collections::BinaryHeap;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let k = k as usize;

    let mut teleport_map = vec![vec![vec![]; n]; m];
    for i in 0..m {
        for j in 0..n {
            for x in 0..m {
                for y in 0..n {
                    if grid[x][y] <= grid[i][j] {
                        teleport_map[i][j].push((x, y));
                    }
                }
            }
        }
    }

    let mut dist = vec![vec![vec![i64::MAX; k + 1]; n]; m];
    dist[0][0][0] = 0;

    let mut pq = BinaryHeap::new();
    pq.push((0, 0, 0, 0));

    while let Some((neg_cost, i, j, t)) = pq.pop() {
        let cost = -neg_cost;
        if cost > dist[i][j][t] {
            continue;
        }

        if i == m - 1 && j == n - 1 {
            return cost;
        }

        let directions = [(0, 1), (1, 0)];
        for (dx, dy) in directions {
            let ni = i as i32 + dx;
            let nj = j as i32 + dy;
            if ni >= 0 && ni < m as i32 && nj >= 0 && nj < n as i32 {
                let ni = ni as usize;
                let nj = nj as usize;
                let new_cost = cost + grid[ni][nj];
                if new_cost < dist[ni][nj][t] {
                    dist[ni][nj][t] = new_cost;
                    pq.push((-new_cost, ni, nj, t));
                }
            }
        }

        if t < k {
            for (x, y) in &teleport_map[i][j] {
                let new_t = t + 1;
                let new_cost = cost;
                if new_cost < dist[*x][*y][new_t] {
                    dist[*x][*y][new_t] = new_cost;
                    pq.push((-new_cost, *x, *y, new_t));
                }
            }
        }
    }

    *dist[m-1][n-1].iter().min().unwrap()
}
